```typescript
function solve(nums: number[]): number {
    function sieve(max: number): boolean[] {
        const isPrime = new Array(max + 1).fill(true);
        isPrime[0] = isPrime[1] = false;
        for (let i = 2; i * i <= max; i++) {
            if (isPrime[i]) {
                for (let j = i * i; j <= max; j += i) {
                    isPrime[j] = false;
                }
            }
        }
        return isPrime;
    }

    function getPrimeFactors(x: number, isPrime: boolean[]): Set<number> {
        const factors = new Set<number>();
        let temp = x;
        for (let i = 2; i * i <= temp; i++) {
            if (temp % i === 0) {
                if (isPrime[i]) {
                    factors.add(i);
                }
                while (temp % i === 0) {
                    temp /= i;
                }
            }
        }
        if (temp > 1) {
            if (isPrime[temp]) {
                factors.add(temp);
            }
        }
        return factors;
    }

    const n = nums.length;
    if (n === 0) return 0;
    if (n === 1) return 0;

    const maxNum = 1000000;
    const isPrime = sieve(maxNum);

    const primeIndices = new Map<number, number[]>();

    for (let j = 0; j < n; j++) {
        const x = nums[j];
        if (x === 1) continue;
        const factors = getPrimeFactors(x, isPrime);
        for (const p of factors) {
            if (!primeIndices.has(p)) {
                primeIndices.set(p, []);
            }
            primeIndices.get(p)!.push(j);
        }
    }

    const visited = new Array(n).fill(-1);
    const queue: [number, number][] = [[0, 0]];
    visited[0] = 0;

    while (queue.length > 0) {
        const [i, steps] = queue.shift()!;
        if (i === n - 1) return steps;

        for (const next of [i - 1, i + 1]) {
            if (next >= 0 && next < n && visited[next] === -1) {
                visited[next] = steps + 1;
                queue.push([next, steps + 1]);
            }
        }

        const p = nums[i];
        if (isPrime[p]) {
            const list = primeIndices.get(p);
            if (list) {
                for (const j of list) {
                    if (j !== i && visited[j] === -1) {
                        visited[j] = steps + 1;
                        queue.push([j, steps + 1]);
                    }
                }
            }
        }
    }

    return -1;
}
